import { describe, expect, test } from "bun:test";
import {
  db,
  email,
  every,
  flow,
  ref,
  s,
  storage,
} from "./index";

describe("@dypai-ai/flow schema helpers", () => {
  test("s helpers produce JSON Schema fragments", () => {
    expect(s.string()).toEqual({ type: "string" });
    expect(s.email()).toEqual({ type: "string", format: "email" });
    expect(s.date()).toEqual({ type: "string", format: "date" });
    expect(s.optional(s.string())).toEqual({ type: "string", optional: true });
  });
});

describe("@dypai-ai/flow ref helpers", () => {
  test("ref helpers produce canonical refs", () => {
    expect(ref.input("email").toRef()).toEqual({ kind: "input", path: ["email"] });
    expect(ref.currentUserId().toRef()).toEqual({ kind: "currentUserId" });
    expect(ref.step("booking", "id").toRef()).toEqual({ kind: "step", stepId: "booking", path: ["id"] });
    expect(ref.literal(true).toRef()).toEqual({ kind: "literal", value: true });
  });
});

describe("flow() builder", () => {
  test("produces FlowDefinition with mapped node calls", () => {
    const definition = flow("create-booking")
      .http({ method: "POST", auth: "jwt" })
      .input({
        name: s.string(),
        email: s.email(),
        date: s.date(),
      })
      .step("booking", db.insert({
        table: "public.bookings",
        values: {
          name: ref.input("name"),
          email: ref.input("email"),
          date: ref.input("date"),
          user_id: ref.currentUserId(),
        },
      }))
      .step("confirmation", email.send({
        to: ref.input("email"),
        subject: "Booking confirmed",
        body: "<p>Confirmed</p>",
      }))
      .return({
        booking: ref.step("booking"),
      });

    expect(definition.name).toBe("create-booking");
    expect(definition.steps[0]?.call).toBe("dypai.db.insert");
    expect(definition.steps[1]?.call).toBe("dypai.email.send");
    expect(definition.auth).toEqual({ mode: "jwt", allowedRoles: [] });
  });

  test("jwt with explicit admin role maps to allowed_roles", () => {
    const definition = flow("admin-dashboard")
      .http({ method: "GET", auth: "jwt", roles: ["admin"] })
      .input({})
      .step("main", db.query({ sql: "SELECT 1" }))
      .return({ ok: ref.literal(true) });

    expect(definition.auth).toEqual({ mode: "jwt", allowedRoles: ["admin"] });
  });

  test("jwt without explicit roles defaults to empty allowed_roles", () => {
    const definition = flow("open-dashboard")
      .http({ method: "GET", auth: "jwt" })
      .input({ _unused: s.optional(s.string()) })
      .step("main", db.query({ sql: "SELECT 1" }))
      .return({ data: ref.step("main") });

    expect(definition.auth).toEqual({ mode: "jwt", allowedRoles: [] });
  });

  test("schedule trigger maps to a server-only flow trigger", () => {
    const definition = flow("daily-cleanup")
      .schedule(every.dayAt("03:00", { timezone: "Europe/Madrid" }))
      .input({})
      .output({ ok: s.boolean() })
      .step("main", db.query({ sql: "SELECT true AS ok" }))
      .return({ ok: ref.step("main", "ok") });

    expect(definition.trigger).toEqual({
      type: "schedule",
      cron: "0 3 * * *",
      timezone: "Europe/Madrid",
    });
    expect(definition.auth).toEqual({ mode: "api_key" });
  });

  test("webhook trigger maps to a server-only external trigger", () => {
    const definition = flow("stripe-payment-succeeded")
      .webhook({ provider: "stripe", event: "payment_intent.succeeded" })
      .input({ id: s.optional(s.string()) })
      .output({ ok: s.boolean() })
      .step("main", db.query({ sql: "SELECT true AS ok" }))
      .return({ ok: ref.step("main", "ok") });

    expect(definition.trigger).toEqual({
      type: "webhook",
      provider: "stripe",
      event: "payment_intent.succeeded",
    });
    expect(definition.auth).toEqual({ mode: "api_key" });
  });

  test("response alias array maps to many", () => {
    const definition = flow("weekly-stats")
      .http({ method: "GET", auth: "jwt" })
      .response("array")
      .input({ _unused: s.optional(s.string()) })
      .step("main", db.query({ sql: "SELECT 1" }))
      .return({ data: ref.step("main") });

    expect(definition.response).toEqual({ cardinality: "many" });
  });

  test("responseCardinality alias maps to response cardinality", () => {
    const definition = flow("get-item")
      .http({ method: "GET", auth: "jwt" })
      .responseCardinality("single")
      .input({ id: s.string() })
      .step("main", db.query({ sql: "SELECT :id AS id", params: { id: ref.input("id") } }))
      .return({ id: ref.step("main", "id") });

    expect(definition.response).toEqual({ cardinality: "single" });
  });

  test("db.query accepts step outputCardinality override", () => {
    const definition = flow("metrics")
      .http({ method: "GET", auth: "jwt" })
      .input({})
      .output({ total: s.number() })
      .step("main", db.query({
        sql: "WITH metrics AS (SELECT COUNT(*)::int AS total FROM public.members) SELECT * FROM metrics",
        outputCardinality: "single",
      }))
      .return({ total: ref.step("main", "total") });

    expect(definition.steps[0]?.config.outputCardinality).toBe("single");
  });

  test("db.query single/maybeSingle/many helpers map to outputCardinality", () => {
    expect(db.query.single({ sql: "SELECT 1 AS ok" }).config.outputCardinality).toBe("single");
    expect(db.query.maybeSingle({ sql: "SELECT * FROM public.members WHERE id = :id" }).config.outputCardinality)
      .toBe("zero_or_one");
    expect(db.query.many({ sql: "SELECT * FROM public.members" }).config.outputCardinality).toBe("many");
  });

  test("db.query fluent helpers do not mutate base query", () => {
    const base = db.query({ sql: "SELECT 1" });
    expect(base.config.outputCardinality).toBeUndefined();
    expect(base.single().config.outputCardinality).toBe("single");
    expect(base.maybeSingle().config.outputCardinality).toBe("zero_or_one");
    expect(base.many().config.outputCardinality).toBe("many");
    expect(base.config.outputCardinality).toBeUndefined();
  });

  test("storage helpers map to dypai.storage capabilities", () => {
    expect(storage.upload({ bucket: "patient-files", path: ref.input("file_path") }).call).toBe(
      "dypai.storage.upload",
    );
    expect(storage.upload({ bucket: "patient-files" }).config).toMatchObject({
      operation: "upload",
      bucket: "patient-files",
    });

    expect(storage.download({ bucket: "docs", path: ref.step("lookup", "storage_path") }).call).toBe(
      "dypai.storage.download",
    );
    expect(storage.download({ bucket: "docs", path: "a.pdf", download: true }).config).toMatchObject({
      operation: "download",
      download: true,
    });

    expect(storage.signedUrl({ bucket: "docs", path: "a.pdf" }).config.download).toBe(false);
    expect(storage.delete({ bucket: "docs", path: "a.pdf" }).call).toBe("dypai.storage.delete");
    expect(storage.read({ bucket: "docs", fileId: ref.input("id") }).call).toBe("dypai.storage.read");
  });
});
